esqlQuery.esql:
// Alert when the Zabbix server item processing queue exceeds a threshold.
// A growing queue indicates the server cannot keep up with incoming data.
// Adjust the threshold in the WHERE clause as needed.
FROM metrics-zabbix.server_health-*
| WHERE zabbix.server.queue.total IS NOT NULL
| STATS max_queue = MAX(zabbix.server.queue.total), max_over_10m = MAX(zabbix.server.queue.over_10m) BY host.name
| WHERE max_queue > 500 OR max_over_10m > 50
